questionvariables.text:
/* Q4: Radiation Pattern Code + Efficiency */
idx: 1 + rand(4);

/* Parameter sets — all satisfy l/lambda < 0.1 (verified) */
/* Set1: 0.5cm/2GHz=0.033, Set2: 1cm/1GHz=0.033, Set3: 1cm/2GHz=0.067, Set4: 2cm/1GHz=0.067 */
l_cm_list: [0.5, 1, 1, 2];
f_GHz_list: [2, 1, 2, 1];
R_loss_list: [0.5, 1, 2, 5];

l_cm: l_cm_list[idx];
f_GHz: f_GHz_list[idx];
R_loss: R_loss_list[idx];

/* Constants */
c0: 3*10^8;

/* Derived */
l_m: l_cm / 100;
f_Hz: f_GHz * 10^9;
lambda_val: float(c0 / f_Hz);
ratio_val: float(l_m / lambda_val);

/* (a) Radiation resistance */
R_rad: float(80 * %pi^2 * ratio_val^2);
tans1: R_rad;

/* (b) Radiation efficiency */
xi: float(R_rad / (R_rad + R_loss));
tans2: xi;

/* (c) Gain in dBi */
G_linear: float(xi * 1.5);
G_dBi: float(10 * log(G_linear) / log(10));
tans3: G_dBi;

/* (d) Angular range upper bound */
tans4: 2*%pi;

/* (e) Power pattern — algebraic expression */
tans5: sin(theta)^2;

/* (f) HPBW angle 1 */
tans6: %pi/4;

/* (g) HPBW angle 2 */
tans7: 3*%pi/4;

/* Error model values */
/* E1: sin(theta) instead of sin(theta)^2 */
pattern_err: sin(theta);
/* E3: efficiency = R_rad/R_loss instead of R_rad/(R_rad+R_loss) */
xi_err: float(R_rad / R_loss);

/* (h) Radiation pattern interpretation MCQ */
ta8: random_permutation([
  [1, true, "No — the dipole radiates zero power along its axis"],
  [2, false, "Yes — the maximum radiation is along the antenna axis"],
  [3, false, "It depends on the operating frequency"],
  [4, false, "It depends on the antenna length"]
]);
correct_h: 1;

/* (i) Negative gain interpretation MCQ */
ta9: random_permutation([
  [1, true, "The antenna radiates less in its peak direction than an isotropic radiator with the same input"],
  [2, false, "The antenna absorbs power instead of radiating it"],
  [3, false, "The radiation pattern has no main lobe"],
  [4, false, "Gain cannot be negative — there must be a calculation error"]
]);
correct_i: 1;
